const Redis = require('ioredis');

const body = $input.first().json.body ?? {};
const contactId = $input.first().json.query?.contactId || body.contactId;

if (!contactId) {
  return [{ json: { success: false, error: 'contactId required' } }];
}

const redis = new Redis({ host: 'redis', port: 6379 });

try {
  const exists = await redis.exists(`contact:${contactId}`);
  if (!exists) {
    await redis.quit();
    return [{ json: { success: false, error: 'Contact not found' } }];
  }

  const updates = {};
  if (body.name !== undefined) updates.name = body.name;
  if (body.whatsappNumber !== undefined) updates.whatsappNumber = body.whatsappNumber;
  if (body.profilePhotoUrl !== undefined) updates.profilePhotoUrl = body.profilePhotoUrl;

  if (Object.keys(updates).length > 0) {
    await redis.hset(`contact:${contactId}`, updates);
  }

  const contact = await redis.hgetall(`contact:${contactId}`);
  await redis.quit();
  return [{ json: { success: true, contactId, ...contact } }];
} catch (err) {
  await redis.quit().catch(() => {});
  throw err;
}
